using UnityEngine;
using System;

/// <summary>
/// Modular health component. Attach to any GameObject that needs HP.
/// Other scripts can GetComponent<HealthComponent>() to read/modify health
/// or subscribe to OnDamaged, OnHealed, OnDeath events.
/// </summary>
public class HealthComponent : MonoBehaviour
{
    [SerializeField] private float maxHealth = 100f;
    [SerializeField] private float armor = 0f;

    public float MaxHealth => maxHealth;
    public float CurrentHealth { get; private set; }
    public float Armor { get => armor; set => armor = Mathf.Max(0f, value); }
    public bool IsAlive => CurrentHealth > 0f;

    // amount = actual damage applied after armor reduction
    public event Action<float> OnDamaged;
    // amount = actual HP restored
    public event Action<float> OnHealed;
    public event Action OnDeath;

    void Awake()
    {
        CurrentHealth = maxHealth;
    }

    /// <summary>Applies damage, accounting for armor. Minimum 1 damage always gets through.</summary>
    public void TakeDamage(float amount)
    {
        if (!IsAlive) return;

        float actual = Mathf.Max(1f, amount - armor);
        CurrentHealth = Mathf.Max(0f, CurrentHealth - actual);

        OnDamaged?.Invoke(actual);

        if (CurrentHealth <= 0f)
            OnDeath?.Invoke();
    }

    /// <summary>Restores HP up to MaxHealth.</summary>
    public void Heal(float amount)
    {
        if (!IsAlive) return;

        float actual = Mathf.Min(amount, maxHealth - CurrentHealth);
        CurrentHealth += actual;
        OnHealed?.Invoke(actual);
    }

    /// <summary>Changes max health. Optionally refills current HP to the new max.</summary>
    public void SetMaxHealth(float newMax, bool refillToMax = false)
    {
        maxHealth = Mathf.Max(1f, newMax);
        CurrentHealth = refillToMax ? maxHealth : Mathf.Min(CurrentHealth, maxHealth);
    }
}
